# Search hadiths for 'تبذر' or 'لا تبذروا' etc
def search_hadith(pattern):
    res=[]
    pat_norm = normalize_ar(pattern)
    for h in hadith_data:
        for field in ('hadithTxt','Matn'):
            txt = h.get(field) or ''
            if not txt: continue
            if normalize_ar(txt).find(pat_norm) != -1:
                res.append((h['hadithID'], field, txt))
                break
    return res

